assert src, '[FAIL] references_v2_autogenerated.bib not found'
SRC = src[0]
OUTDIR = os.path.dirname(SRC)
print('[src]', SRC)

raw = open(SRC, 'r', encoding='utf-8', errors='replace').read()

# ---------- parse v2 entries (brace-counting) ----------
def parse_bib(text):
    entries, i, n = [], 0, len(text)
    while True:
        m = re.search(r'@(\w+)\s*\{', text[i:])
        if not m: break
        start = i + m.start(); j = i + m.end(); depth = 1
        while j < n and depth > 0:
            if text[j] == '{': depth += 1
            elif text[j] == '}': depth -= 1
            j += 1
        block = text[start:j]
        km = re.match(r'@\w+\s*\{\s*([^,\s]+)\s*,', block)
        key = km.group(1) if km else None
        entries.append({'key': key, 'type': m.group(1).lower(), 'block': block})
        i = j
    return entries

v2 = parse_bib(raw)
v2keys = [e['key'] for e in v2]
print('[v2] entries:', len(v2))
dups = sorted({k for k in v2keys if v2keys.count(k) > 1})
if dups: print('[WARN] duplicate keys inside v2:', dups)

