def rekey(block, newkey):
    return re.sub(r'(@\w+\s*\{\s*)[^,\s]+(\s*,)', r'\g<1>'+newkey+r'\g<2>', block, count=1)

replaced, appended, purged = [], [], []
out_entries = []
consumed = set()

for e in v2:
    k = e['key'] or ''
    if 'loveland' in k.lower():
        purged.append(k); continue
    matched = None
    for canon, body in ADJ.items():
        if canon in consumed: continue
        if k == canon or k in ALIASES.get(canon, []):
            matched = canon; break
    if matched:
        out_entries.append(rekey(ADJ[matched], k))  # preserve existing key
        replaced.append((k, matched)); consumed.add(matched)
    else:
        out_entries.append(e['block'])

for canon, body in ADJ.items():
    if canon not in consumed:
        out_entries.append(body); appended.append(canon)

header = ('% references_v3_merged.bib generated ' + str(datetime.date.today()) +
          ' by CELL BIB-3 from references_v2_autogenerated.bib\n'
          '% per BIB_ADJUDICATION_FINAL_v1; existing cite keys preserved on replacement.\n\n')
merged = header + '\n\n'.join(out_entries) + '\n'
OUT = os.path.join(OUTDIR, 'references_v3_merged.bib')
open(OUT, 'w', encoding='utf-8').write(merged)

# ---------- report ----------
print('\n[REPLACED]', len(replaced))
for k, c in replaced: print('   kept key', k, '<- adjudicated', c)
print('[APPENDED]', len(appended))
for c in appended: print('   +', c)
print('[PURGED]', purged if purged else 'none')
v3 = parse_bib(merged)
print('[v3] entries:', len(v3))
keys3 = sorted([x['key'] for x in v3])
print('[v3 keys]'); print(', '.join(keys3))
dois = {}
for x in v3:
    dm = re.search(r'doi\s*=\s*\{([^}]+)\}', x['block'], re.I)
    if dm: dois.setdefault(dm.group(1).strip().lower(), []).append(x['key'])
dupdoi = {d: ks for d, ks in dois.items() if len(ks) > 1}
print('[DOI duplicates across keys]', dupdoi if dupdoi else 'none')
em = merged.count('\u2014')
print('[em-dash U+2014 chars in v3]', em, '(titles should use TeX --- instead)' if em else '')
print('[saved]', OUT)
print('[DONE BIB-3]')
